import{_ as o,o as a,c as d,ak as i}from"./chunks/framework.BbJJwCwT.js";const g=JSON.parse('{"title":"Changelog","description":"All notable changes to foreblocks — release notes and version history.","frontmatter":{"title":"Changelog","description":"All notable changes to foreblocks — release notes and version history.","editLink":true,"foreBlocksVersion":"0.1.34"},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),l={name:"changelog.md"};function t(r,e,n,c,s,h){return a(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to “Changelog”">​</a></h1><p>Release history for <code>foreblocks</code> and <code>foretools</code>.</p><h2 id="v0-1-15-current" tabindex="-1">v0.1.15 (current) <a class="header-anchor" href="#v0-1-15-current" aria-label="Permalink to “v0.1.15 (current)”">​</a></h2><h3 id="foreblocks" tabindex="-1">foreblocks <a class="header-anchor" href="#foreblocks" aria-label="Permalink to “foreblocks”">​</a></h3><ul><li>Added <code>mHC</code> (multi-Hyper-Connections) residual stream mixing to <code>TransformerEncoder</code> and <code>TransformerDecoder</code></li><li>Added paper-style Attention Residuals (<code>use_attention_residual</code>, <code>attn_residual_type</code>, <code>attention_residual_block_size</code>)</li><li>Added Mixture-of-Depths token routing (<code>use_mod</code>, <code>mod_mode</code>, <code>mod_budget_scheduler</code>)</li><li>Added latent-MoE path (<code>moe_use_latent</code>, <code>moe_latent_dim</code>, <code>moe_latent_d_ff</code>) for higher expert count at lower cost</li><li>Added <code>adaptive_noisy_topk</code>, <code>hash_topk</code>, and <code>multi_hash_topk</code> router families</li><li>Added <code>afocp</code> conformal method with attention-based feature network</li><li>Added <code>cptc</code> (state-aware rolling conformal) method</li><li>Removed classic dense load-balancing auxiliary loss; expert utilization now handled via router expert-bias adaptation</li><li><code>label_len &lt;= 0</code> in Informer-like mode no longer generates a full-decoder Informer padding mask</li><li><code>forward_one_step(...)</code> is now incompatible with <code>use_mod=True</code> and <code>use_mhc=True</code> (explicitly guarded)</li></ul><h3 id="foretools" tabindex="-1">foretools <a class="header-anchor" href="#foretools" aria-label="Permalink to “foretools”">​</a></h3><ul><li>Added <code>tsgen</code> synthetic series generator with AR, seasonal, trend, and noise components</li><li>Added <code>tsaug</code> AutoDA augmentation search</li><li>Added <code>foreminer</code> changepoint detection, cluster analysis, and stationarity diagnostics</li><li><code>bohb</code> plotter and observation store improvements</li></ul><h3 id="breaking-changes" tabindex="-1">Breaking changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to “Breaking changes”">​</a></h3><ul><li>Code importing <code>TimeSeriesSeq2Seq</code> directly should switch to <code>ForecastingModel</code></li><li><code>load_balance_weight</code> no longer drives the primary balancing mechanism in MoE; tune <code>z_loss_weight</code> and router type instead</li></ul><hr><h2 id="v0-1-14" tabindex="-1">v0.1.14 <a class="header-anchor" href="#v0-1-14" aria-label="Permalink to “v0.1.14”">​</a></h2><ul><li>Initial public release of <code>foretools/bohb</code> Bayesian hyperparameter optimization</li><li>Added <code>ConformalPredictionEngine</code> with <code>split</code>, <code>rolling</code>, <code>agaci</code>, and <code>enbpi</code> methods</li><li>Added <code>GateSkip</code> sublayer-level residual gating</li><li>Added CT-PatchTST encoder tokenization path (<code>ct_patchtst=True</code>)</li><li>Added <code>foretools/fengineer</code> feature engineering pipeline with RFECV and mutual-information selection</li><li>Added <code>foretools/vmd</code> decomposition toolkit (VMD, EMD-family, hierarchical VMD)</li><li>Stabilized <code>MLTracker</code> local FastAPI server and <code>mltracker-tui</code> TUI</li></ul><hr><h2 id="v0-1-x-and-earlier" tabindex="-1">v0.1.x and earlier <a class="header-anchor" href="#v0-1-x-and-earlier" aria-label="Permalink to “v0.1.x and earlier”">​</a></h2><p>See <a href="https://github.com/lseman/foreblocks/commits/main" target="_blank" rel="noreferrer">git log</a> for commit-level history.</p>',15)])])}const u=o(l,[["render",t]]);export{g as __pageData,u as default};
